#!/usr/bin/env python3
"""Phase 2 Situational Awareness — AI/ML Environment Scanner.
Detects local AI/ML infrastructure: Ollama, MLX, LM Studio, HuggingFace,
OpenAI/Anthropic API keys, model caches, running inference servers.
Any local LLM is a potential tool for data analysis or social engineering."""

import os
import sys
import json
import re
import socket
import platform
import subprocess
from pathlib import Path

HOME = Path.home()
RESULTS = {"host": os.uname().nodename, "sections": {}}

# ── 1. Ollama ──
def scan_ollama():
    result = {"installed": False, "running": False, "models": []}
    # Check if binary exists
    try:
        proc = subprocess.run(["which", "ollama"], capture_output=True, text=True, timeout=5)
        result["installed"] = proc.returncode == 0
        if result["installed"]:
            result["binary"] = proc.stdout.strip()
    except (FileNotFoundError, subprocess.TimeoutExpired):
        pass
    # Check if running (default port 11434)
    try:
        s = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        s.settimeout(2)
        s.connect(("127.0.0.1", 11434))
        s.close()
        result["running"] = True
        # Query API for models
        s2 = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        s2.settimeout(5)
        s2.connect(("127.0.0.1", 11434))
        req = b"GET /api/tags HTTP/1.1\r\nHost: localhost\r\nConnection: close\r\n\r\n"
        s2.sendall(req)
        resp = b""
        while True:
            chunk = s2.recv(4096)
            if not chunk:
                break
            resp += chunk
        s2.close()
        body = resp.split(b"\r\n\r\n", 1)[-1]
        try:
            data = json.loads(body)
            for model in data.get("models", []):
                result["models"].append({
                    "name": model.get("name"),
                    "size": model.get("size"),
                    "modified": model.get("modified_at", "")[:19],
                })
        except json.JSONDecodeError:
            pass
    except (ConnectionRefusedError, socket.timeout, OSError):
        pass
    # Check model cache directory
    ollama_dirs = [
        HOME / ".ollama" / "models",
        Path("/usr/share/ollama/.ollama/models"),
    ]
    for od in ollama_dirs:
        if od.exists():
            result["cache_dir"] = str(od)
            try:
                manifests = list((od / "manifests").rglob("*"))
                result["cached_models"] = len([m for m in manifests if m.is_file()])
            except (PermissionError, OSError):
                pass
    return result

# ── 2. HuggingFace ──
def scan_huggingface():
    result = {"cache_found": False}
    hf_cache = HOME / ".cache" / "huggingface"
    if hf_cache.exists():
        result["cache_found"] = True
        result["cache_path"] = str(hf_cache)
        # List cached models
        hub_dir = hf_cache / "hub"
        if hub_dir.exists():
            models = []
            for model_dir in sorted(hub_dir.iterdir()):
                if model_dir.is_dir() and model_dir.name.startswith("models--"):
                    name = model_dir.name.replace("models--", "").replace("--", "/")
                    # Get size
                    try:
                        total = sum(f.stat().st_size for f in model_dir.rglob("*") if f.is_file())
                        models.append({"name": name, "size_mb": round(total / 1024 / 1024, 1)})
                    except (PermissionError, OSError):
                        models.append({"name": name})
            result["models"] = models
    # HF token
    hf_token = hf_cache / "token" if hf_cache.exists() else HOME / ".huggingface" / "token"
    if hf_token.exists():
        try:
            token = hf_token.read_text().strip()
            result["token"] = token[:8] + "..." + token[-4:] if len(token) > 12 else "present"
        except (PermissionError, OSError):
            result["token"] = "exists_but_unreadable"
    return result

# ── 3. LM Studio ──
def scan_lm_studio():
    result = {"installed": False}
    lms_dirs = [
        HOME / ".lmstudio",
        HOME / "Library" / "Application Support" / "LM Studio",
        HOME / ".cache" / "lm-studio",
    ]
    for ld in lms_dirs:
        if ld.exists():
            result["installed"] = True
            result["path"] = str(ld)
            # Check for models
            models_dir = HOME / ".cache" / "lm-studio" / "models"
            if not models_dir.exists():
                models_dir = ld / "models"
            if models_dir.exists():
                result["models"] = []
                for m in sorted(models_dir.iterdir()):
                    if m.is_dir():
                        result["models"].append(m.name)
            break
    # Check if API is running (default port 1234)
    try:
        s = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        s.settimeout(2)
        s.connect(("127.0.0.1", 1234))
        s.close()
        result["api_running"] = True
    except (ConnectionRefusedError, socket.timeout, OSError):
        result["api_running"] = False
    return result

# ── 4. MLX (Apple Silicon) ──
def scan_mlx():
    result = {"available": False}
    if platform.machine() != "arm64" or platform.system() != "Darwin":
        return result
    try:
        proc = subprocess.run([sys.executable, "-c", "import mlx; print(mlx.__version__)"],
                              capture_output=True, text=True, timeout=10)
        if proc.returncode == 0:
            result["available"] = True
            result["version"] = proc.stdout.strip()
    except (FileNotFoundError, subprocess.TimeoutExpired):
        pass
    # MLX model cache
    mlx_cache = HOME / ".cache" / "mlx"
    if mlx_cache.exists():
        result["cache_path"] = str(mlx_cache)
        try:
            models = [d.name for d in mlx_cache.iterdir() if d.is_dir()]
            result["cached_models"] = models
        except (PermissionError, OSError):
            pass
    return result

# ── 5. API Keys (OpenAI, Anthropic, etc.) ──
def scan_ai_api_keys():
    result = {}
    key_vars = {
        "openai": ["OPENAI_API_KEY", "OPENAI_KEY"],
        "anthropic": ["ANTHROPIC_API_KEY", "CLAUDE_API_KEY"],
        "google_ai": ["GOOGLE_API_KEY", "GEMINI_API_KEY"],
        "cohere": ["COHERE_API_KEY", "CO_API_KEY"],
        "replicate": ["REPLICATE_API_TOKEN"],
        "huggingface": ["HF_TOKEN", "HUGGING_FACE_HUB_TOKEN"],
        "together": ["TOGETHER_API_KEY"],
        "groq": ["GROQ_API_KEY"],
        "mistral": ["MISTRAL_API_KEY"],
        "perplexity": ["PERPLEXITY_API_KEY"],
    }
    for provider, vars_list in key_vars.items():
        for var in vars_list:
            val = os.environ.get(var)
            if val:
                result[provider] = {"var": var, "preview": val[:8] + "..." + val[-4:]}
                break
    # Also check common config files
    openai_key_file = HOME / ".openai" / "api_key"
    if openai_key_file.exists():
        try:
            key = openai_key_file.read_text().strip()
            result["openai_file"] = {"path": str(openai_key_file), "preview": key[:8] + "..."}
        except (PermissionError, OSError):
            pass
    return result

# ── 6. Running AI Services ──
def scan_running_services():
    result = {"services": []}
    ai_ports = {
        5000: "Flask/MLflow", 8000: "FastAPI/vLLM", 8080: "TGI/LocalAI",
        8501: "Streamlit", 7860: "Gradio", 3000: "Dify/LangServe",
        1234: "LM Studio", 11434: "Ollama", 9090: "Prometheus",
        5001: "MLflow", 4000: "LiteLLM", 6333: "Qdrant",
        8983: "Solr", 19530: "Milvus", 6334: "Qdrant-gRPC",
    }
    for port, name in ai_ports.items():
        try:
            s = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
            s.settimeout(0.5)
            if s.connect_ex(("127.0.0.1", port)) == 0:
                result["services"].append({"port": port, "name": name})
            s.close()
        except OSError:
            pass
    return result

# ── Run all ──
for name, fn in [("ollama", scan_ollama), ("huggingface", scan_huggingface),
                  ("lm_studio", scan_lm_studio), ("mlx", scan_mlx),
                  ("ai_api_keys", scan_ai_api_keys), ("running_services", scan_running_services)]:
    try:
        RESULTS["sections"][name] = fn()
    except Exception as e:
        RESULTS["sections"][name] = {"error": str(e)}

print(json.dumps(RESULTS, indent=2, default=str))
print(f"\n[*] AI/ML scan complete")
for k, v in RESULTS["sections"].items():
    if isinstance(v, dict):
        status = []
        if v.get("installed") or v.get("available") or v.get("cache_found"):
            status.append("FOUND")
        if v.get("running") or v.get("api_running"):
            status.append("RUNNING")
        models = v.get("models", [])
        if models:
            status.append(f"{len(models)} models")
        print(f"  {k}: {', '.join(status) if status else 'not found'}")

