#!/usr/bin/env python3
"""Phase 2 Situational Awareness — Full Network Discovery.
Collects ARP table, routing table, DNS cache, active connections,
SMB shares, NFS mounts, printers, IoT/IP cameras, network interfaces.
Not just IPs — services, versions, banners."""

import os
import sys
import json
import re
import socket
import struct
import platform
import subprocess
from concurrent.futures import ThreadPoolExecutor, as_completed
from ipaddress import IPv4Network, IPv4Address

SYSTEM = platform.system()
RESULTS = {"host": os.uname().nodename, "sections": {}}

# ── 1. Network Interfaces ──
def get_interfaces():
    result = []
    try:
        if SYSTEM == "Linux":
            proc = subprocess.run(["ip", "-j", "addr"], capture_output=True, text=True, timeout=5)
            if proc.returncode == 0:
                data = json.loads(proc.stdout)
                for iface in data:
                    info = {"name": iface["ifname"], "state": iface.get("operstate"),
                            "mac": iface.get("address"), "addrs": []}
                    for ai in iface.get("addr_info", []):
                        info["addrs"].append({"ip": ai.get("local"), "prefix": ai.get("prefixlen"),
                                              "family": ai.get("family")})
                    result.append(info)
        elif SYSTEM == "Darwin":
            proc = subprocess.run(["ifconfig"], capture_output=True, text=True, timeout=5)
            if proc.returncode == 0:
                current = None
                for line in proc.stdout.split("\n"):
                    m = re.match(r'^(\w+):', line)
                    if m:
                        if current:
                            result.append(current)
                        current = {"name": m.group(1), "addrs": []}
                    elif current:
                        ip_m = re.search(r'inet (\d+\.\d+\.\d+\.\d+)', line)
                        if ip_m:
                            current["addrs"].append({"ip": ip_m.group(1), "family": "inet"})
                        mac_m = re.search(r'ether (\S+)', line)
                        if mac_m:
                            current["mac"] = mac_m.group(1)
                if current:
                    result.append(current)
    except (FileNotFoundError, subprocess.TimeoutExpired, json.JSONDecodeError):
        pass
    return result

# ── 2. ARP Table ──
def get_arp_table():
    result = []
    try:
        if SYSTEM == "Linux":
            proc = subprocess.run(["ip", "neigh", "show"], capture_output=True, text=True, timeout=5)
        else:
            proc = subprocess.run(["arp", "-a"], capture_output=True, text=True, timeout=5)
        if proc.returncode == 0:
            for line in proc.stdout.strip().split("\n"):
                if line.strip():
                    result.append(line.strip()[:120])
    except (FileNotFoundError, subprocess.TimeoutExpired):
        pass
    return result

# ── 3. Routing Table ──
def get_routes():
    result = []
    try:
        if SYSTEM == "Linux":
            proc = subprocess.run(["ip", "route", "show"], capture_output=True, text=True, timeout=5)
        else:
            proc = subprocess.run(["netstat", "-rn"], capture_output=True, text=True, timeout=5)
        if proc.returncode == 0:
            for line in proc.stdout.strip().split("\n"):
                if line.strip():
                    result.append(line.strip()[:120])
    except (FileNotFoundError, subprocess.TimeoutExpired):
        pass
    return result

# ── 4. DNS Cache ──
def get_dns_cache():
    result = {"entries": []}
    try:
        if SYSTEM == "Linux":
            # systemd-resolved
            proc = subprocess.run(["resolvectl", "statistics"], capture_output=True, text=True, timeout=5)
            if proc.returncode == 0:
                result["resolver_stats"] = proc.stdout[:500]
        elif SYSTEM == "Darwin":
            # macOS DNS cache dump requires admin, but we can check resolv.conf
            pass
    except (FileNotFoundError, subprocess.TimeoutExpired):
        pass
    # /etc/resolv.conf
    try:
        with open("/etc/resolv.conf", "r") as f:
            content = f.read()
        result["nameservers"] = re.findall(r'nameserver\s+(\S+)', content)
        result["search_domains"] = re.findall(r'search\s+(.+)', content)
    except (PermissionError, FileNotFoundError):
        pass
    # /etc/hosts
    try:
        with open("/etc/hosts", "r") as f:
            hosts = [l.strip() for l in f if l.strip() and not l.startswith("#")]
        result["hosts_entries"] = len(hosts)
    except (PermissionError, FileNotFoundError):
        pass
    return result

# ── 5. Active Connections (netstat) ──
def get_connections():
    result = {"listening": [], "established": []}
    try:
        if SYSTEM == "Linux":
            proc = subprocess.run(["ss", "-tulnp"], capture_output=True, text=True, timeout=5)
        else:
            proc = subprocess.run(["netstat", "-an"], capture_output=True, text=True, timeout=5)
        if proc.returncode == 0:
            for line in proc.stdout.strip().split("\n"):
                line = line.strip()
                if "LISTEN" in line:
                    result["listening"].append(line[:150])
                elif "ESTABLISHED" in line or "ESTAB" in line:
                    result["established"].append(line[:150])
    except (FileNotFoundError, subprocess.TimeoutExpired):
        pass
    return result

# ── 6. SMB Shares ──
def scan_smb_shares():
    result = {"shares": []}
    # Find hosts with port 445 open on local subnet
    try:
        local_ip = socket.gethostbyname(socket.gethostname())
    except socket.gaierror:
        return result
    subnet = ".".join(local_ip.split(".")[:3]) + ".0/24"
    try:
        network = IPv4Network(subnet, strict=False)
    except ValueError:
        return result

    def check_smb(ip):
        ip_str = str(ip)
        try:
            s = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
            s.settimeout(0.5)
            if s.connect_ex((ip_str, 445)) == 0:
                s.close()
                return ip_str
            s.close()
        except OSError:
            pass
        return None

    with ThreadPoolExecutor(max_workers=30) as ex:
        futures = {ex.submit(check_smb, ip): ip for ip in list(network.hosts())[:254]}
        for f in as_completed(futures, timeout=15):
            try:
                ip = f.result()
                if ip:
                    result["shares"].append({"host": ip, "port": 445})
            except Exception:
                pass
    return result

# ── 7. NFS Mounts ──
def get_nfs_mounts():
    result = {"current": [], "exports": []}
    try:
        proc = subprocess.run(["mount"], capture_output=True, text=True, timeout=5)
        if proc.returncode == 0:
            for line in proc.stdout.split("\n"):
                if "nfs" in line.lower() or "cifs" in line.lower():
                    result["current"].append(line.strip()[:120])
    except (FileNotFoundError, subprocess.TimeoutExpired):
        pass
    # Check /etc/exports for NFS server
    try:
        with open("/etc/exports", "r") as f:
            result["exports"] = [l.strip() for l in f if l.strip() and not l.startswith("#")][:20]
    except (PermissionError, FileNotFoundError):
        pass
    return result

# ── 8. Printers ──
def get_printers():
    result = []
    try:
        proc = subprocess.run(["lpstat", "-a"], capture_output=True, text=True, timeout=5)
        if proc.returncode == 0:
            for line in proc.stdout.strip().split("\n"):
                if line.strip():
                    result.append(line.strip()[:100])
    except (FileNotFoundError, subprocess.TimeoutExpired):
        pass
    # Also check for network printers on common ports
    return result

# ── 9. IoT / IP Cameras (port scan common IoT ports) ──
def scan_iot_devices():
    result = []
    iot_ports = {
        554: "RTSP (IP Camera)", 8554: "RTSP-Alt",
        80: "HTTP (Web UI)", 8080: "HTTP-Alt",
        1883: "MQTT (IoT)", 8883: "MQTT-TLS",
        5353: "mDNS/Bonjour", 9100: "Printer-JetDirect",
        631: "CUPS/IPP", 161: "SNMP", 502: "Modbus",
        1900: "UPnP/SSDP", 5683: "CoAP (IoT)",
    }
    try:
        local_ip = socket.gethostbyname(socket.gethostname())
    except socket.gaierror:
        return result
    subnet_prefix = ".".join(local_ip.split(".")[:3])

    def probe_host(ip_int):
        ip = f"{subnet_prefix}.{ip_int}"
        found = []
        for port, desc in iot_ports.items():
            try:
                s = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
                s.settimeout(0.3)
                if s.connect_ex((ip, port)) == 0:
                    found.append({"port": port, "service": desc})
                s.close()
            except OSError:
                pass
        return (ip, found) if found else None

    with ThreadPoolExecutor(max_workers=30) as ex:
        futures = [ex.submit(probe_host, i) for i in range(1, 255)]
        for f in as_completed(futures, timeout=30):
            try:
                r = f.result()
                if r:
                    result.append({"host": r[0], "services": r[1]})
            except Exception:
                pass
    return result

# ── Run all ──
for name, fn in [("interfaces", get_interfaces), ("arp", get_arp_table),
                  ("routes", get_routes), ("dns", get_dns_cache),
                  ("connections", get_connections), ("smb", scan_smb_shares),
                  ("nfs", get_nfs_mounts), ("printers", get_printers),
                  ("iot_devices", scan_iot_devices)]:
    try:
        RESULTS["sections"][name] = fn()
    except Exception as e:
        RESULTS["sections"][name] = {"error": str(e)}

print(json.dumps(RESULTS, indent=2, default=str))
print(f"\n[*] Network discovery complete — {len(RESULTS['sections'])} sections")
for k, v in RESULTS["sections"].items():
    if isinstance(v, list):
        print(f"  {k}: {len(v)} entries")
    elif isinstance(v, dict):
        if "error" in v:
            print(f"  {k}: error")
        else:
            for sub_k, sub_v in v.items():
                if isinstance(sub_v, list) and sub_v:
                    print(f"  {k}.{sub_k}: {len(sub_v)} entries")

