#!/usr/bin/env python3
"""Phase 2 Situational Awareness — Full Cloud Enumerator.
Enumerates AWS (IAM, S3, EC2, Lambda), Azure (subscriptions, managed identities,
VMs, storage), GCP (projects, instances, buckets), and Kubernetes (pods, secrets,
service accounts, RBAC). One tool to sweep all cloud footprint."""

import os
import sys
import json
import subprocess
import platform
from pathlib import Path

HOME = Path.home()
RESULTS = {"sections": {}}

def _run(cmd, timeout=15):
    try:
        proc = subprocess.run(cmd, capture_output=True, text=True, timeout=timeout)
        if proc.returncode == 0:
            try:
                return json.loads(proc.stdout)
            except json.JSONDecodeError:
                return {"raw": proc.stdout[:2000]}
    except (FileNotFoundError, subprocess.TimeoutExpired):
        pass
    return None

# ── 1. AWS ──
def enum_aws():
    result = {"available": False}
    # Check for credentials
    aws_creds = HOME / ".aws" / "credentials"
    if aws_creds.exists():
        result["credentials_file"] = True
        try:
            import configparser
            cp = configparser.ConfigParser()
            cp.read(str(aws_creds))
            result["profiles"] = cp.sections()
        except Exception:
            pass
    # Caller identity
    identity = _run(["aws", "sts", "get-caller-identity", "--output", "json"])
    if identity:
        result["available"] = True
        result["identity"] = identity
    else:
        return result
    # IAM
    users = _run(["aws", "iam", "list-users", "--output", "json"])
    if users:
        result["iam_users"] = len(users.get("Users", []))
    roles = _run(["aws", "iam", "list-roles", "--output", "json"])
    if roles:
        result["iam_roles"] = len(roles.get("Roles", []))
    # My IAM policies
    my_arn = identity.get("Arn", "")
    if ":user/" in my_arn:
        username = my_arn.split("/")[-1]
        policies = _run(["aws", "iam", "list-attached-user-policies",
                         "--user-name", username, "--output", "json"])
        if policies:
            result["my_policies"] = [p["PolicyName"] for p in policies.get("AttachedPolicies", [])]
    # S3
    buckets = _run(["aws", "s3api", "list-buckets", "--output", "json"])
    if buckets:
        result["s3_buckets"] = [b["Name"] for b in buckets.get("Buckets", [])][:20]
    # EC2
    instances = _run(["aws", "ec2", "describe-instances", "--output", "json"])
    if instances:
        all_instances = []
        for res in instances.get("Reservations", []):
            for inst in res.get("Instances", []):
                name_tag = next((t["Value"] for t in inst.get("Tags", []) if t["Key"] == "Name"), "")
                all_instances.append({"id": inst["InstanceId"], "type": inst["InstanceType"],
                                       "state": inst["State"]["Name"], "name": name_tag})
        result["ec2_instances"] = all_instances[:20]
    # Lambda
    lambdas = _run(["aws", "lambda", "list-functions", "--output", "json"])
    if lambdas:
        result["lambda_functions"] = [f["FunctionName"] for f in lambdas.get("Functions", [])][:20]
    # Secrets Manager
    secrets = _run(["aws", "secretsmanager", "list-secrets", "--output", "json"])
    if secrets:
        result["secrets_manager"] = [s["Name"] for s in secrets.get("SecretList", [])][:20]
    return result

# ── 2. Azure ──
def enum_azure():
    result = {"available": False}
    # Check for az CLI
    accounts = _run(["az", "account", "list", "--output", "json"])
    if accounts:
        result["available"] = True
        if isinstance(accounts, list):
            result["subscriptions"] = [{"name": a.get("name"), "id": a.get("id"),
                                         "state": a.get("state")} for a in accounts]
        elif isinstance(accounts, dict) and "raw" in accounts:
            result["subscriptions_raw"] = accounts["raw"][:500]
    else:
        return result
    # Current user
    user = _run(["az", "ad", "signed-in-user", "show", "--output", "json"])
    if user:
        result["current_user"] = {"upn": user.get("userPrincipalName"),
                                   "display": user.get("displayName")}
    # VMs
    vms = _run(["az", "vm", "list", "--output", "json"])
    if vms and isinstance(vms, list):
        result["vms"] = [{"name": v.get("name"), "rg": v.get("resourceGroup"),
                          "location": v.get("location")} for v in vms[:20]]
    # Storage accounts
    storage = _run(["az", "storage", "account", "list", "--output", "json"])
    if storage and isinstance(storage, list):
        result["storage_accounts"] = [s.get("name") for s in storage[:20]]
    # Key Vaults
    vaults = _run(["az", "keyvault", "list", "--output", "json"])
    if vaults and isinstance(vaults, list):
        result["key_vaults"] = [v.get("name") for v in vaults[:20]]
    # Managed Identities
    mi = _run(["az", "identity", "list", "--output", "json"])
    if mi and isinstance(mi, list):
        result["managed_identities"] = [{"name": i.get("name"), "rg": i.get("resourceGroup")} for i in mi[:10]]
    return result

# ── 3. GCP ──
def enum_gcp():
    result = {"available": False}
    # Auth list
    auth = _run(["gcloud", "auth", "list", "--format", "json"])
    if auth and isinstance(auth, list):
        result["available"] = True
        result["accounts"] = [{"account": a.get("account"), "status": a.get("status")} for a in auth]
    else:
        return result
    # Projects
    projects = _run(["gcloud", "projects", "list", "--format", "json"])
    if projects and isinstance(projects, list):
        result["projects"] = [{"id": p.get("projectId"), "name": p.get("name")} for p in projects[:10]]
    # Instances
    instances = _run(["gcloud", "compute", "instances", "list", "--format", "json"])
    if instances and isinstance(instances, list):
        result["instances"] = [{"name": i.get("name"), "zone": i.get("zone", "").split("/")[-1],
                                 "status": i.get("status")} for i in instances[:20]]
    # GCS Buckets
    buckets = _run(["gsutil", "ls"])
    if buckets and isinstance(buckets, dict) and "raw" in buckets:
        result["buckets"] = [l.strip() for l in buckets["raw"].strip().split("\n") if l.strip()][:20]
    return result

# ── 4. Kubernetes ──
def enum_kubernetes():
    result = {"available": False}
    # Context
    ctx = _run(["kubectl", "config", "current-context"])
    if ctx:
        result["available"] = True
        result["context"] = ctx.get("raw", str(ctx))[:200]
    else:
        return result
    # Namespaces
    ns = _run(["kubectl", "get", "namespaces", "-o", "json"])
    if ns:
        result["namespaces"] = [n["metadata"]["name"] for n in ns.get("items", [])]
    # Pods
    pods = _run(["kubectl", "get", "pods", "--all-namespaces", "-o", "json"], timeout=20)
    if pods:
        result["pods"] = [{"ns": p["metadata"]["namespace"], "name": p["metadata"]["name"],
                           "phase": p["status"].get("phase")} for p in pods.get("items", [])][:30]
    # Secrets
    secrets = _run(["kubectl", "get", "secrets", "--all-namespaces", "-o", "json"])
    if secrets:
        result["secrets"] = [{"ns": s["metadata"]["namespace"], "name": s["metadata"]["name"],
                              "type": s.get("type")} for s in secrets.get("items", [])][:30]
    # Service accounts
    sa = _run(["kubectl", "get", "serviceaccounts", "--all-namespaces", "-o", "json"])
    if sa:
        result["service_accounts"] = len(sa.get("items", []))
    # RBAC
    crb = _run(["kubectl", "get", "clusterrolebindings", "-o", "json"])
    if crb:
