#!/usr/bin/env python3
"""Phase 2 Situational Awareness — Full Active Directory Enumerator.
Covers Domain Controllers, Domain Admins, Kerberoastable (SPN accounts),
AS-REP Roastable, GPO enumeration, Trust Relationships, LAPS, gMSA,
and ADCS Certificate Templates (ESC1-ESC8 for privilege escalation).
All via LDAP queries — no external dependencies."""

import subprocess
import sys
import json
import re
import os
import socket

DOMAIN = os.environ.get("AD_DOMAIN", "{domain}")
DC_IP = os.environ.get("AD_DC", "{dc_ip}")
USERNAME = os.environ.get("AD_USER", "{username}")
PASSWORD = os.environ.get("AD_PASS", "{password}")

RESULTS = {"domain": DOMAIN, "dc": DC_IP, "sections": {}}

def _ldap(base_dn, ldap_filter, attributes, scope="sub"):
    """Run ldapsearch and return raw output."""
    cmd = ["ldapsearch", "-x", "-H", f"ldap://{DC_IP}",
           "-D", f"{USERNAME}@{DOMAIN}", "-w", PASSWORD,
           "-b", base_dn, "-s", scope, ldap_filter] + attributes
    try:
        proc = subprocess.run(cmd, capture_output=True, text=True, timeout=30)
        return proc.stdout if proc.returncode == 0 else ""
    except (FileNotFoundError, subprocess.TimeoutExpired):
        return ""

def _parse_ldap(output, fields):
    """Parse ldapsearch output into list of dicts."""
    entries = []
    current = {}
    for line in output.split("\n"):
        line = line.strip()
        if line.startswith("dn:"):
            if current:
                entries.append(current)
            current = {"dn": line[3:].strip()}
        else:
            for f in fields:
                if line.startswith(f + ":"):
                    val = line.split(":", 1)[1].strip()
                    if f in current:
                        if isinstance(current[f], list):
                            current[f].append(val)
                        else:
                            current[f] = [current[f], val]
                    else:
                        current[f] = val
    if current:
        entries.append(current)
    return entries

def get_base_dn():
    parts = DOMAIN.split(".")
    return ",".join(f"DC={p}" for p in parts)

# ── 1. Domain Controllers ──
def enum_domain_controllers():
    base = get_base_dn()
    output = _ldap(f"OU=Domain Controllers,{base}",
                   "(objectCategory=computer)",
                   ["dNSHostName", "operatingSystem", "operatingSystemVersion"])
    return _parse_ldap(output, ["dNSHostName", "operatingSystem", "operatingSystemVersion"])

# ── 2. Domain Admins ──
def enum_domain_admins():
    base = get_base_dn()
    output = _ldap(base, "(&(objectCategory=group)(cn=Domain Admins))",
                   ["member"])
    entries = _parse_ldap(output, ["member"])
    members = []
    for e in entries:
        m = e.get("member", [])
        if isinstance(m, str):
            m = [m]
        members.extend(m)
    return members

# ── 3. Kerberoastable Accounts (SPN set on user accounts) ──
def enum_kerberoastable():
    base = get_base_dn()
    output = _ldap(base,
                   "(&(objectClass=user)(servicePrincipalName=*)(!(objectClass=computer))(!(userAccountControl:1.2.840.113556.1.4.803:=2)))",
                   ["sAMAccountName", "servicePrincipalName", "adminCount", "memberOf"])
    return _parse_ldap(output, ["sAMAccountName", "servicePrincipalName", "adminCount", "memberOf"])

# ── 4. AS-REP Roastable (no preauth required) ──
def enum_asrep_roastable():
    base = get_base_dn()
    # UF_DONT_REQUIRE_PREAUTH = 0x400000 = 4194304
    output = _ldap(base,
                   "(&(objectClass=user)(userAccountControl:1.2.840.113556.1.4.803:=4194304)(!(objectClass=computer)))",
                   ["sAMAccountName", "userAccountControl", "memberOf"])
    return _parse_ldap(output, ["sAMAccountName", "userAccountControl", "memberOf"])

# ── 5. GPO Enumeration ──
def enum_gpos():
    base = get_base_dn()
    output = _ldap(f"CN=Policies,CN=System,{base}",
                   "(objectClass=groupPolicyContainer)",
                   ["displayName", "gPCFileSysPath", "cn"])
    return _parse_ldap(output, ["displayName", "gPCFileSysPath", "cn"])

# ── 6. Trust Relationships ──
def enum_trusts():
    base = get_base_dn()
    output = _ldap(f"CN=System,{base}",
                   "(objectClass=trustedDomain)",
                   ["cn", "trustDirection", "trustType", "trustAttributes", "flatName"])
    entries = _parse_ldap(output, ["cn", "trustDirection", "trustType", "trustAttributes", "flatName"])
    # Decode trust direction
    for e in entries:
        td = e.get("trustDirection", "0")
        try:
            td = int(td)
            e["direction"] = {0: "Disabled", 1: "Inbound", 2: "Outbound", 3: "Bidirectional"}.get(td, str(td))
        except ValueError:
            pass
    return entries

# ── 7. LAPS Passwords ──
def enum_laps():
    base = get_base_dn()
    # Try to read ms-Mcs-AdmPwd (LAPS v1) or msLAPS-Password (LAPS v2)
    output = _ldap(base,
                   "(&(objectCategory=computer)(ms-Mcs-AdmPwd=*))",
                   ["dNSHostName", "ms-Mcs-AdmPwd", "ms-Mcs-AdmPwdExpirationTime"])
    v1 = _parse_ldap(output, ["dNSHostName", "ms-Mcs-AdmPwd", "ms-Mcs-AdmPwdExpirationTime"])
    output2 = _ldap(base,
                    "(&(objectCategory=computer)(msLAPS-Password=*))",
                    ["dNSHostName", "msLAPS-Password"])
    v2 = _parse_ldap(output2, ["dNSHostName", "msLAPS-Password"])
    return {"laps_v1": v1, "laps_v2": v2}

# ── 8. gMSA (Group Managed Service Accounts) ──
def enum_gmsa():
    base = get_base_dn()
    output = _ldap(base,
                   "(objectClass=msDS-GroupManagedServiceAccount)",
                   ["sAMAccountName", "msDS-ManagedPasswordInterval",
                    "msDS-GroupMSAMembership", "servicePrincipalName"])
    return _parse_ldap(output, ["sAMAccountName", "msDS-ManagedPasswordInterval",
                                 "msDS-GroupMSAMembership", "servicePrincipalName"])

# ── 9. ADCS Certificate Templates (ESC1-ESC8) ──
def enum_adcs():
    base = get_base_dn()
    config_dn = f"CN=Configuration,{base}"
    # Find Certificate Authorities
    ca_output = _ldap(f"CN=Enrollment Services,CN=Public Key Services,CN=Services,{config_dn}",
                      "(objectClass=pKIEnrollmentService)",
                      ["cn", "dNSHostName", "certificateTemplates"])
    cas = _parse_ldap(ca_output, ["cn", "dNSHostName", "certificateTemplates"])
    # Find Certificate Templates
    tmpl_output = _ldap(f"CN=Certificate Templates,CN=Public Key Services,CN=Services,{config_dn}",
                        "(objectClass=pKICertificateTemplate)",
                        ["cn", "displayName", "msPKI-Certificate-Name-Flag",
                         "msPKI-Enrollment-Flag", "pKIExtendedKeyUsage",
                         "msPKI-RA-Signature", "msPKI-Certificate-Application-Policy"])
    templates = _parse_ldap(tmpl_output, ["cn", "displayName", "msPKI-Certificate-Name-Flag",
                                           "msPKI-Enrollment-Flag", "pKIExtendedKeyUsage",
                                           "msPKI-RA-Signature", "msPKI-Certificate-Application-Policy"])
    # ESC1 check: ENROLLEE_SUPPLIES_SUBJECT flag (0x1) + Client Auth EKU
    esc_vulnerable = []
    for t in templates:
        flags = t.get("msPKI-Certificate-Name-Flag", "0")
        try:
            flags = int(flags)
        except ValueError:
            flags = 0
        eku = t.get("pKIExtendedKeyUsage", "")
        if isinstance(eku, list):
            eku = " ".join(eku)
        ra_sig = t.get("msPKI-RA-Signature", "0")
        try:
            ra_sig = int(ra_sig)
        except ValueError:
            ra_sig = 0
        vulns = []
        # ESC1: Subject name supplied by enrollee + Client Auth
        if (flags & 1) and ("1.3.6.1.5.5.7.3.2" in eku or "Client Auth" in eku):
            vulns.append("ESC1")
        # ESC2: Any Purpose EKU or no EKU
        if "2.5.29.37.0" in eku or not eku:
            vulns.append("ESC2")
        # ESC3: Certificate Request Agent + no RA signature required
        if "1.3.6.1.4.1.311.20.2.1" in eku and ra_sig == 0:
            vulns.append("ESC3")
        if vulns:
            esc_vulnerable.append({"template": t.get("cn", t.get("displayName")),
                                    "vulnerabilities": vulns, "flags": flags})
    return {"cas": cas, "templates_total": len(templates), "esc_vulnerable": esc_vulnerable}

# ── Run all ──
base = get_base_dn()
for name, fn in [("domain_controllers", enum_domain_controllers),
                  ("domain_admins", enum_domain_admins),
                  ("kerberoastable", enum_kerberoastable),
                  ("asrep_roastable", enum_asrep_roastable),
                  ("gpos", enum_gpos),
                  ("trusts", enum_trusts),
                  ("laps", enum_laps),
                  ("gmsa", enum_gmsa),
                  ("adcs", enum_adcs)]:
    try:
        RESULTS["sections"][name] = fn()
    except Exception as e:
        RESULTS["sections"][name] = {"error": str(e)}

print(json.dumps(RESULTS, indent=2, default=str))
print(f"\n[*] AD enumeration complete — {len(RESULTS['sections'])} sections")
for k, v in RESULTS["sections"].items():
    if isinstance(v, list):
        print(f"  {k}: {len(v)} entries")
    elif isinstance(v, dict):
        if "error" in v:
            print(f"  {k}: error")
        else:
            for sub_k, sub_v in v.items():
                if isinstance(sub_v, list):
                    print(f"  {k}.{sub_k}: {len(sub_v)} entries")
